void DM1_Flt_Scan_Check(void) //ЙЪеЯЩЈУшМьВт
{
	uint16_t ListCrtFltNum = 0; //ЕБЧАСаБэжаЙЪеЯЗЂЩњЪ§СП
	uint16_t BMSListCrtFltNum = 0; //BMSЕБЧАСаБэжаЙЪеЯЗЂЩњЪ§СП
	
	icuCrtFltNum = 0;
	if(M_ON_flag) //вЧБэЗЂЫЭЙЪеЯжЛдкдПГзONЕЕМьВт
		ICU_DM1_Handler();
	for(uint32_t cnt = 0; cnt < DM1_LIST_FLT_NUM; cnt++)
	{
		if(DMPackage[cnt].SourceAdress != 0x17) //ТдЙ§вЧБэЗЂЫЭЕФDM1ЙЪеЯМьВт
		{
			DMPackage[cnt].set = 0;
		}
		else
		{
			if(M_ON_flag)
			{
				if(DMPackage[cnt].set == 1)
				{
					icuCrtDM1Flt[icuCrtFltNum].SPN = DMPackage[cnt].spn;
					icuCrtDM1Flt[icuCrtFltNum].FMI = DMPackage[cnt].fmi;
					icuCrtDM1Flt[icuCrtFltNum].OC  = 0x7F; //OCЮДЖЈ,ЩшЮЊШЋ1
					icuCrtDM1Flt[icuCrtFltNum].CM  = 0;    //CM = 0
					icuCrtFltNum++; //вЧБэЗЂЩњЙЪеЯЪ§СП
					if(icuCrtFltNum > ICU_MAX_ERR_NUM)
						icuCrtFltNum = ICU_MAX_ERR_NUM;
					
					ListCrtFltPos[ListCrtFltNum] = cnt;
					ListCrtFltNum++;
					
				}
			}
		}
		
	}
	for(uint8_t owner = 0; owner < DM1_OWNER_NUM; owner++)
	{
		for(uint32_t num = 0; num < CurrentFltInfo[owner].FltNum; num++)
		{
			for(uint32_t cnt = 0; cnt < DM1_LIST_FLT_NUM; cnt++)
			{
				if((DMPackage[cnt].SourceAdress == CurrentFltInfo[owner].SA)
				&& (DMPackage[cnt].spn == CurrentFltInfo[owner].FltBuf.DTC[num].SPN) \
				&& (DMPackage[cnt].fmi == CurrentFltInfo[owner].FltBuf.DTC[num].FMI))
				{
					if(0x0B == CurrentFltInfo[owner].SA)
					{
						if(8 == eol_ebs) //ABS-КгФЯНЙзї
						{
							if((cnt >= 174) && (cnt <= 197))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else if(11U == eol_ebs) //ABS-KNORR
						{
							if((cnt >= 198) && (cnt <= 422))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else if(6 == eol_ebs) //EBS-KNORR
						{
							if((cnt >= 423) && (cnt <= 1207))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else
						{
							//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
							break;
						}
					}
					else if(0xE8 == CurrentFltInfo[owner].SA || 0xA0 == CurrentFltInfo[owner].SA || 0x2A == CurrentFltInfo[owner].SA)
					{
						if(0x03 == eol_aebstype) //дТееЫЩAEBS
						{
							if((cnt>= 1677)&&(cnt <= 1752))//дТееЫЩAEBS
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
							else
							{
								//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
								break;
							}
						}
						else if(0x02 == eol_aebstype) //KnorrAEBS
						{
							if((cnt>= 1753)&&(cnt <= 1885))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
							else
							{
								//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
								break;
							}
						}
						else
						{
							//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
							break;
						}
					}
					else if(0x33 == CurrentFltInfo[owner].SA)
					{
						if((eol_tpmsyesno > 0) && (eol_tpmsyesno < 6))
						{
							DMPackage[cnt].set = 1;
							ListCrtFltPos[ListCrtFltNum] = cnt;
							ListCrtFltNum++;
							break;
						}
						else
						{
							//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
							break;
						}
					}
					else if(0xF6 == CurrentFltInfo[owner].SA)
					{
						if(0x2d == eol_fadongjiorkaji)
						{
							DMPackage[cnt].set = 1;
							ListCrtFltPos[ListCrtFltNum] = cnt;
							ListCrtFltNum++;
							break;
						}
						else
						{
							//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
							break;
						}
					}
					else if(0x2F == CurrentFltInfo[owner].SA)
					{
						if(0x05 == eol_ecastype)//Ш№СЂECAS
						{
							if((cnt >= 1968) && (cnt <= 2028))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else if(0x03 == eol_ecastype)//Wabco ECAS
						{
							if((cnt >= 2029) && (cnt <= 2122))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else if(0x04 == eol_ecastype)//Knorr ECAS
						{
							if((cnt >= 2123) && (cnt <= 2186))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else
						{
							//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
							break;
						}
					}
					else if(0x50 == CurrentFltInfo[owner].SA)
					{
						if(1 == eol_epbtype)//ПЦУмШ№СЂEPB
						{
							if((cnt >= 2566) && (cnt <= 2602))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else if(2 == eol_epbtype) //Knorr EPB
						{
							if((cnt >= 2603) && (cnt <= 2657))
							{
								DMPackage[cnt].set = 1;
								ListCrtFltPos[ListCrtFltNum] = cnt;
								ListCrtFltNum++;
								break;
							}
						}
						else
						{
							//днВЛжЇГжЦфЫћБъЖЈЕФЙЪеЯТы
							break;
						}
					}
					else
					{
						DMPackage[cnt].set = 1;
						ListCrtFltPos[ListCrtFltNum] = cnt;
						ListCrtFltNum++;
						
						if(0xF4 == CurrentFltInfo[owner].SA)
						{
							bmsListCrtFltPos[BMSListCrtFltNum] = cnt;
							BMSListCrtFltNum++;
						}
						
						break;
					}
				}
				
			}
		
		}
		
	}
	
	/* for(uint32_t cnt = 0; cnt < DM1_LIST_FLT_NUM; cnt++)
	{
		if(DMPackage[cnt].set == 1)
		{
			ListCrtFltNum ++;
			
			if(DMPackage[cnt].SourceAdress == 0x17)
				icuCrtFltNum++;
			
		}
	} */
	
	if(BMSListCrtFltNum > 99)
		BMSListCrtFltNum = 99;
	bmsCrtFltNum = BMSListCrtFltNum;
	
	if(ListCrtFltNum > 99)
		ListCrtFltNum = 99;
	TotalDM = ListCrtFltNum;
	
}

bool get_dm1_flt_status(uint8_t owner, uint32_t spn, uint8_t fmi)
{
	bool ret = false;
	
	if(owner < DM1_OWNER_NUM)
	{
		for(uint8_t i = 0; i < CurrentFltInfo[owner].FltNum;i++)
		{
			if((spn == CurrentFltInfo[owner].FltBuf.DTC[i].SPN) \
			&& (fmi == CurrentFltInfo[owner].FltBuf.DTC[i].FMI))
			{
				ret = true;
				break;
			}
		}
	}
	return ret;
}




